1	/* ============================================================
2	   Hero — pinned, scroll-scrubbed cinematic. The 3D screen-reveal
3	   pop-out is baked into the video itself (last ~2s = camera pulls
4	   back to reveal the cinema monitor), so the website's only job is
5	   to scrub the canvas and fade brand copy on top.
6	
7	   Layer stack (back → front):
8	     .hero
9	     ├── canvas (fills section, painted by FrameCanvas)
10	     ├── .copyLayer  (brand mark / headline / tagline / CTA)
11	     ├── .scrollHint
12	     └── .loader     (front-most until frames preload)
13	   ============================================================ */
14	
15	.hero {
16	  position: relative;
17	  width: 100%;
18	  height: 100vh;
19	  overflow: hidden;
20	  background: var(--ink);
21	  isolation: isolate;
22	  font-family: var(--font-display);
23	}
24	
25	.canvas {
26	  position: absolute;
27	  inset: 0;
28	  width: 100%;
29	  height: 100%;
30	  display: block;
31	  z-index: 1;
32	}
33	
34	/* ---------- Copy layer ---------- */
35	.copyLayer {
36	  position: absolute;
37	  inset: 0;
38	  z-index: 4;
39	  display: grid;
40	  grid-template-rows: 1fr auto 1fr;
41	  align-items: stretch;
42	  justify-items: center;
43	  padding: clamp(24px, 5vw, 64px);
44	  pointer-events: none;
45	}
46	
47	.copyLayer > * {
48	  pointer-events: auto;
49	}
50	
51	.heroCopy {
52	  grid-row: 1 / 2;
53	  align-self: end;
54	  text-align: center;
55	  color: var(--paper);
56	  text-shadow: 0 2px 24px rgba(0, 0, 0, 0.5);
57	  margin-bottom: clamp(24px, 4vh, 48px);
58	  opacity: 0;
59	}
60	
61	.brandMark {
62	  display: inline-block;
63	  font-family: var(--font-display);
64	  font-weight: 500;
65	  font-size: clamp(11px, 1vw, 13px);
66	  letter-spacing: 0.42em;
67	  text-indent: 0.42em;
68	  color: rgba(255, 255, 255, 0.82);
69	  margin-bottom: clamp(16px, 2vh, 24px);
70	}
71	
72	.headline {
73	  font-family: var(--font-display);
74	  font-weight: 600;
75	  font-size: clamp(48px, 9vw, 132px);
76	  line-height: 0.92;
77	  letter-spacing: -0.04em;
78	  color: var(--paper);
79	}
80	
81	.tagline {
82	  grid-row: 2 / 3;
83	  align-self: center;
84	  font-family: var(--font-display);
85	  font-weight: 400;
86	  font-size: clamp(18px, 1.6vw, 22px);
87	  letter-spacing: 0.01em;
88	  color: var(--paper);
89	  text-align: center;
90	  text-shadow: 0 2px 24px rgba(0, 0, 0, 0.5);
91	  opacity: 0;
92	}
93	
94	.cta {
95	  grid-row: 3 / 4;
96	  align-self: end;
97	  display: inline-flex;
98	  align-items: center;
99	  gap: 12px;
100	  padding: 14px 26px;
101	  border-radius: 999px;
102	  background: var(--paper);
103	  color: var(--ink);
104	  font-family: var(--font-display);
105	  font-weight: 500;
106	  font-size: 15px;
107	  letter-spacing: 0.02em;
108	  opacity: 0;
109	  transition: background 0.35s var(--ease-out-cubic), color 0.35s var(--ease-out-cubic), transform 0.35s var(--ease-out-cubic);
110	  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.35);
111	}
112	
113	.cta:hover {
114	  background: var(--amber);
115	  color: var(--ink);
116	  transform: translateY(-2px);
117	}
118	
119	.cta svg {
120	  transition: transform 0.35s var(--ease-out-cubic);
121	}
122	
123	.cta:hover svg {
124	  transform: translateX(4px);
125	}
126	
127	/* ---------- Scroll hint ---------- */
128	.scrollHint {
129	  position: absolute;
130	  bottom: clamp(20px, 4vh, 40px);
131	  left: 50%;
132	  transform: translateX(-50%);
133	  z-index: 4;
134	  display: flex;
135	  flex-direction: column;
136	  align-items: center;
137	  gap: 12px;
138	  color: rgba(255, 255, 255, 0.7);
139	  font-family: var(--font-display);
140	  font-weight: 500;
141	  font-size: 11px;
142	  letter-spacing: 0.4em;
143	  text-indent: 0.4em;
144	}
145	
146	.scrollHintLine {
147	  width: 1px;
148	  height: 36px;
149	  background: linear-gradient(to bottom, rgba(255, 255, 255, 0.6), rgba(255, 255, 255, 0));
150	  position: relative;
151	  overflow: hidden;
152	}
153	
154	.scrollHintLine::after {
155	  content: '';
156	  position: absolute;
157	  inset: 0;
158	  background: linear-gradient(to bottom, rgba(255, 255, 255, 0.95), rgba(255, 255, 255, 0));
159	  animation: scrollPulse 1.8s ease-in-out infinite;
160	}
161	
162	@keyframes scrollPulse {
163	  0%   { transform: translateY(-100%); }
164	  100% { transform: translateY(100%);  }
165	}
166	
167	/* ---------- Loader ---------- */
168	.loader {
169	  position: absolute;
170	  inset: 0;
171	  z-index: 10;
172	  background: var(--ink);
173	  display: grid;
174	  place-items: center;
175	  transition: opacity 0.6s var(--ease-out-cubic), visibility 0s linear 0.6s;
176	}
177	
178	.loader[data-ready='true'] {
179	  opacity: 0;
180	  visibility: hidden;
181	  pointer-events: none;
182	}
183	
184	.loaderInner {
185	  display: grid;
186	  grid-template-columns: 1fr auto 1fr;
187	  align-items: center;
188	  gap: 24px;
189	  width: min(560px, 70vw);
190	  color: var(--paper);
191	}
192	
193	.loaderMark {
194	  font-family: var(--font-display);
195	  font-weight: 600;
196	  letter-spacing: 0.4em;
197	  font-size: 14px;
198	  justify-self: start;
199	}
200	
201	.loaderCount {
202	  font-family: var(--font-display);
203	  font-weight: 500;
204	  font-size: 14px;
205	  font-variant-numeric: tabular-nums;
206	  letter-spacing: 0.06em;
207	  color: rgba(255, 255, 255, 0.65);
208	}
209	
210	.loaderBar {
211	  grid-column: 1 / -1;
212	  width: 100%;
213	  height: 1px;
214	  background: rgba(255, 255, 255, 0.12);
215	  overflow: hidden;
216	}
217	
218	.loaderBarFill {
219	  width: 100%;
220	  height: 100%;
221	  background: var(--paper);
222	  transform-origin: left;
223	  transform: scaleX(0);
224	  transition: transform 0.25s var(--ease-out-cubic);
225	}
226	
227	@media (prefers-reduced-motion: reduce) {
228	  .scrollHintLine::after {
229	    animation: none;
230	  }
231	}
232	
233	@media (max-width: 720px) {
234	  .copyLayer { padding: 24px 16px; }
235	}
