1	*,
2	*::before,
3	*::after {
4	  box-sizing: border-box;
5	  margin: 0;
6	  padding: 0;
7	}
8	
9	html,
10	body {
11	  background: var(--ink);
12	  color: var(--ink);
13	  font-family: var(--font-body);
14	  font-size: 16px;
15	  line-height: 1.5;
16	  -webkit-font-smoothing: antialiased;
17	  -moz-osx-font-smoothing: grayscale;
18	  text-rendering: optimizeLegibility;
19	}
20	
21	body {
22	  overflow-x: hidden;
23	}
24	
25	img,
26	picture,
27	video,
28	canvas {
29	  display: block;
30	  max-width: 100%;
31	}
32	
33	button {
34	  font: inherit;
35	  color: inherit;
36	  background: none;
37	  border: none;
38	  cursor: pointer;
39	}
40	
41	a {
42	  color: inherit;
43	  text-decoration: none;
44	}
45	
46	::selection {
47	  background: var(--cobalt);
48	  color: var(--paper);
49	}
50	
51	/* Lenis disables native smooth scroll while it's active */
52	html.lenis,
53	html.lenis body {
54	  height: auto;
55	}
56	
57	.lenis.lenis-smooth {
58	  scroll-behavior: auto !important;
59	}
60	
61	.lenis.lenis-smooth [data-lenis-prevent] {
62	  overscroll-behavior: contain;
63	}
64	
65	.lenis.lenis-stopped {
66	  overflow: hidden;
67	}
68	
69	.lenis.lenis-scrolling iframe {
70	  pointer-events: none;
71	}
