1	:root {
2	  --ink: #0a0d12;
3	  --ink-soft: #1c2230;
4	  --cobalt: #1e3a8a;
5	  --cobalt-glow: rgba(30, 58, 138, 0.35);
6	  --sky: #d8e6f5;
7	  --sky-deep: #6aa6ff;
8	  --cirrus: #f6f9fd;
9	  --paper: #ffffff;
10	  --paper-warm: #fbfbf9;
11	  --amber: #f4b15c;
12	  --glass: rgba(255, 255, 255, 0.55);
13	  --glass-edge: rgba(255, 255, 255, 0.65);
14	  --glass-tint: rgba(255, 255, 255, 0.06);
15	
16	  --font-display: 'Inter Tight', system-ui, -apple-system, sans-serif;
17	  --font-body: 'Inter', system-ui, -apple-system, sans-serif;
18	
19	  --space-1: 8px;
20	  --space-2: 16px;
21	  --space-3: 24px;
22	  --space-4: 40px;
23	  --space-5: 64px;
24	  --space-6: 96px;
25	
26	  --radius-stage: 28px;
27	  --shadow-stage: 0 30px 80px -20px var(--cobalt-glow), 0 4px 20px -4px rgba(10, 13, 18, 0.18);
28	
29	  --ease-out-cubic: cubic-bezier(0.215, 0.61, 0.355, 1);
30	  --ease-in-out: cubic-bezier(0.65, 0, 0.35, 1);
31	}
